using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }

    public void Heal(int amount)
    {
        health += amount;
        if (health > 100) health = 100;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            return true;
        }
        return false;
    }
}

public class Shop : MonoBehaviour
{
    public Player player;

    public void PurchaseItem(int price)
    {
        if (player.SpendCurrency(price))
        {
            // Grant item to player
        }
        else
        {
            Debug.Log("Not enough currency");
        }
    }

    public int CalculateItemPrice(int basePrice, int level)
    {
        return basePrice * level;
    }
}

public class GameManager : MonoBehaviour
{
    public Player player;
    public Shop shop;

    void Start()
    {
        player = new Player();
        shop = new Shop { player = player };
    }

    void Update()
    {
        // Example usage
        if (Input.GetKeyDown(KeyCode.Space))
        {
            player.TakeDamage(10);
        }

        if (Input.GetKeyDown(KeyCode.H))
        {
            player.Heal(10);
        }

        if (Input.GetKeyDown(KeyCode.B))
        {
            int price = shop.CalculateItemPrice(10, 1);
            shop.PurchaseItem(price);
        }
    }
}